                <select className="w-full border border-gray-300 rounded-lg p-2.5 bg-white text-gray-900 focus:ring-2 focus:ring-blue-500 focus:outline-none" value={formData.category} onChange={e => setFormData({...formData, category: e.target.value as Category})}>
