import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useStore } from '../context/StoreContext';
import { MessageCircle, CreditCard, CheckCircle } from 'lucide-react';

const Checkout: React.FC = () => {
  const { cart, clearCart, getThemeClasses, siteConfig } = useStore();
  const theme = getThemeClasses();
  const navigate = useNavigate();
  const total = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);

  const [formData, setFormData] = useState({
    name: '',
    email: '',
    phone: '',
    address: '',
    city: '',
  });

  const [isProcessing, setIsProcessing] = useState(false);
  const [orderComplete, setOrderComplete] = useState(false);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleWhatsAppOrder = (e: React.FormEvent) => {
    e.preventDefault();
    setIsProcessing(true);

    // Build WhatsApp Message
    let message = `*Nuevo Pedido IDO*\n\n`;
    message += `*Cliente:* ${formData.name}\n`;
    message += `*Dirección:* ${formData.address}, ${formData.city}\n\n`;
    message += `*Detalle:*\n`;
    cart.forEach(item => {
      message += `- ${item.quantity}x ${item.name}: $${(item.price * item.quantity).toFixed(2)}\n`;
    });
    message += `\n*TOTAL: $${total.toFixed(2)}*`;

    const encodedMessage = encodeURIComponent(message);
    const whatsappUrl = `https://wa.me/${siteConfig.contactPhone.replace(/[^0-9]/g, '')}?text=${encodedMessage}`;

    // Simulate slight delay for UX
    setTimeout(() => {
      window.open(whatsappUrl, '_blank');
      setOrderComplete(true);
      clearCart();
      setIsProcessing(false);
    }, 1500);
  };

  if (cart.length === 0 && !orderComplete) {
     navigate('/catalog');
     return null;
  }

  if (orderComplete) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center p-4">
        <div className="bg-white p-8 rounded-2xl shadow-lg max-w-md w-full text-center animate-fade-in">
          <div className={`w-20 h-20 ${theme.bg} rounded-full flex items-center justify-center mx-auto mb-6 text-white`}>
            <CheckCircle size={40} />
          </div>
          <h2 className="text-2xl font-bold text-gray-900 mb-2">¡Pedido Solicitado!</h2>
          <p className="text-gray-500 mb-8">
            Hemos redirigido tu pedido a WhatsApp para coordinar el pago y envío.
          </p>
          <button
            onClick={() => navigate('/')}
            className={`w-full py-3 px-4 rounded-lg text-white font-medium ${theme.bg} ${theme.hover} transition-colors`}
          >
            Volver al Inicio
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 py-12">
      <div className="max-w-3xl mx-auto px-4 sm:px-6 lg:px-8">
        <h1 className="text-3xl font-bold text-gray-900 mb-8 text-center">Finalizar Compra</h1>

        <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
          <div className="p-8">
            <form onSubmit={handleWhatsAppOrder} className="space-y-6">

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                  <label htmlFor="name" className="block text-sm font-medium text-gray-700 mb-1">Nombre Completo</label>
                  <input
                    type="text"
                    name="name"
                    required
                    className="w-full rounded-lg border-gray-300 border px-3 py-2 bg-white text-gray-900 focus:ring-2 focus:ring-emerald-500 focus:outline-none"
                    value={formData.name}
                    onChange={handleChange}
                  />
                </div>
                <div>
                  <label htmlFor="phone" className="block text-sm font-medium text-gray-700 mb-1">Teléfono</label>
                  <input
                    type="tel"
                    name="phone"
                    required
                    className="w-full rounded-lg border-gray-300 border px-3 py-2 bg-white text-gray-900 focus:ring-2 focus:ring-emerald-500 focus:outline-none"
                    value={formData.phone}
                    onChange={handleChange}
                  />
                </div>
              </div>

              <div>
                <label htmlFor="email" className="block text-sm font-medium text-gray-700 mb-1">Correo Electrónico</label>
                <input
                  type="email"
                  name="email"
                  required
                  className="w-full rounded-lg border-gray-300 border px-3 py-2 bg-white text-gray-900 focus:ring-2 focus:ring-emerald-500 focus:outline-none"
                  value={formData.email}
                  onChange={handleChange}
                />
              </div>

              <div>
                <label htmlFor="address" className="block text-sm font-medium text-gray-700 mb-1">Dirección de Entrega</label>
                <textarea
                  name="address"
                  required
                  rows={3}
                  className="w-full rounded-lg border-gray-300 border px-3 py-2 bg-white text-gray-900 focus:ring-2 focus:ring-emerald-500 focus:outline-none"
                  value={formData.address}
                  onChange={handleChange}
                ></textarea>
              </div>

              <div>
                <label htmlFor="city" className="block text-sm font-medium text-gray-700 mb-1">Ciudad / Estado</label>
                <input
                  type="text"
                  name="city"
                  required
                  className="w-full rounded-lg border-gray-300 border px-3 py-2 bg-white text-gray-900 focus:ring-2 focus:ring-emerald-500 focus:outline-none"
                  value={formData.city}
                  onChange={handleChange}
                />
              </div>

              <div className="bg-gray-50 p-4 rounded-lg flex justify-between items-center mt-6">
                <span className="font-semibold text-gray-700">Total a Pagar:</span>
                <span className="text-2xl font-bold text-gray-900">${total.toFixed(2)}</span>
              </div>

              <div className="pt-4 space-y-3">
                 <button
                  type="submit"
                  disabled={isProcessing}
                  className="w-full flex items-center justify-center gap-2 bg-[#25D366] hover:bg-[#20bd5a] text-white py-4 rounded-xl font-bold text-lg shadow-md transition-all disabled:opacity-70"
                >
                  {isProcessing ? 'Procesando...' : (
                    <>
                      <MessageCircle size={24} /> Pedir por WhatsApp
                    </>
                  )}
                </button>
                <div className="text-center text-xs text-gray-500">
                   Al hacer clic, se abrirá WhatsApp con los detalles de tu pedido.
                </div>

                <button
                   type="button"
                   disabled
                   className="w-full flex items-center justify-center gap-2 bg-gray-100 text-gray-400 py-3 rounded-xl font-semibold cursor-not-allowed"
                   title="Integración Stripe/PayPal disponible en versión completa"
                >
                  <CreditCard size={20} /> Pagar con Tarjeta (Próximamente)
                </button>
              </div>

            </form>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Checkout;

import React, { useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { Minus, Plus, ShoppingCart, ArrowLeft, CheckCircle } from 'lucide-react';
import { useStore } from '../context/StoreContext';

const ProductDetail: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { products, addToCart, getThemeClasses } = useStore();
  const theme = getThemeClasses();

  const product = products.find(p => p.id === id);
  const [quantity, setQuantity] = useState(1);
  const [showSuccess, setShowSuccess] = useState(false);

  if (!product) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="text-center">
          <h2 className="text-2xl font-bold text-gray-800">Producto no encontrado</h2>
          <button onClick={() => navigate('/catalog')} className={`mt-4 ${theme.text} hover:underline`}>
            Volver al catálogo
          </button>
        </div>
      </div>
    );
  }

  const handleAddToCart = () => {
    addToCart(product, quantity);
    setShowSuccess(true);
    setTimeout(() => setShowSuccess(false), 3000);
  };

  const increment = () => setQuantity(q => q + 1);
  const decrement = () => setQuantity(q => (q > 1 ? q - 1 : 1));

  return (
    <div className="min-h-screen bg-gray-50 py-12">
      <div className="max-w-6xl mx-auto px-4 sm:px-6 lg:px-8">
        <button 
          onClick={() => navigate(-1)}
          className="flex items-center text-gray-500 hover:text-gray-900 mb-8 transition-colors"
        >
          <ArrowLeft size={20} className="mr-2" />
          Volver
        </button>

        <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
          <div className="grid grid-cols-1 md:grid-cols-2">
            {/* Image Side */}
            <div className="bg-gray-100 p-8 flex items-center justify-center">
              <img 
                src={product.imageUrl} 
                alt={product.name} 
                className="max-h-[500px] w-full object-contain mix-blend-multiply"
              />
            </div>

            {/* Content Side */}
            <div className="p-8 md:p-12 flex flex-col justify-center">
              <span className={`inline-block px-3 py-1 rounded-full text-xs font-semibold ${theme.bg} bg-opacity-10 ${theme.text} w-fit mb-4`}>
                {product.category}
              </span>

              <h1 className="text-3xl md:text-4xl font-bold text-gray-900 mb-4">
                {product.name}
              </h1>

              <p className="text-gray-600 text-lg leading-relaxed mb-8">
                {product.description}
              </p>

              <div className="flex items-end gap-4 mb-8">
                <span className={`text-4xl font-bold ${theme.text}`}>
                  ${product.price.toFixed(2)}
                </span>
                <span className="text-gray-500 mb-2">/ unidad</span>
              </div>

              <div className="border-t border-b border-gray-100 py-6 mb-8">
                <div className="flex items-center gap-6">
                  <div className="flex items-center border border-gray-300 rounded-lg">
                    <button 
                      onClick={decrement}
                      className="px-4 py-2 hover:bg-gray-50 text-gray-600 transition-colors"
                    >
                      <Minus size={18} />
                    </button>
                    <input 
                      type="number" 
                      min="1" 
                      value={quantity} 
                      onChange={(e) => setQuantity(Math.max(1, parseInt(e.target.value) || 1))}
                      className="w-16 text-center border-x border-gray-300 py-2 focus:outline-none bg-white text-gray-900"
                    />
                    <button 
                      onClick={increment}
                      className="px-4 py-2 hover:bg-gray-50 text-gray-600 transition-colors"
                    >
                      <Plus size={18} />
                    </button>
                  </div>

                  {product.stock > 0 ? (
                    <span className="text-green-600 text-sm font-medium flex items-center">
                      <CheckCircle size={16} className="mr-1" /> Disponibilidad inmediata
                    </span>
                  ) : (
                    <span className="text-red-500 text-sm font-medium">Agotado</span>
                  )}
                </div>
              </div>

              <button
                onClick={handleAddToCart}
                disabled={product.stock === 0}
                className={`w-full py-4 rounded-xl font-bold text-lg text-white shadow-lg flex items-center justify-center gap-3 transition-all transform active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed ${theme.bg} ${theme.hover}`}
              >
                <ShoppingCart size={24} />
                {showSuccess ? '¡Añadido!' : 'Añadir al Carrito'}
              </button>

              {showSuccess && (
                <div className="mt-4 p-4 bg-green-50 text-green-700 rounded-lg border border-green-200 animate-fade-in flex items-center justify-center">
                  <CheckCircle size={20} className="mr-2" />
                  Producto añadido correctamente
                </div>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ProductDetail;

import React, { useState, useEffect } from 'react';
import { useSearchParams } from 'react-router-dom';
import { Search, Filter } from 'lucide-react';
import { useStore } from '../context/StoreContext';
import ProductCard from '../components/ProductCard';
import { CATEGORIES } from '../constants';

const Catalog: React.FC = () => {
  const { products, getThemeClasses } = useStore();
  const theme = getThemeClasses();
  const [searchParams, setSearchParams] = useSearchParams();

  const initialCategory = searchParams.get('category') || 'Todas';

  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCategory, setSelectedCategory] = useState(initialCategory);

  useEffect(() => {
    // Update URL when category changes locally
    if (selectedCategory === 'Todas') {
      searchParams.delete('category');
    } else {
      searchParams.set('category', selectedCategory);
    }
    setSearchParams(searchParams);
  }, [selectedCategory, searchParams, setSearchParams]);

  const filteredProducts = products.filter(product => {
    const matchesSearch = product.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
                          product.description.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesCategory = selectedCategory === 'Todas' || product.category === selectedCategory;
    return matchesSearch && matchesCategory;
  });

  return (
    <div className="min-h-screen bg-gray-50 py-12">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <h1 className="text-3xl font-bold text-gray-900 mb-8">Catálogo de Productos</h1>

        <div className="flex flex-col md:flex-row gap-6 mb-8">
          {/* Search */}
          <div className="relative flex-grow">
            <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
              <Search className="h-5 w-5 text-gray-400" />
            </div>
            <input
              type="text"
              className={`block w-full pl-10 pr-3 py-3 border border-gray-300 rounded-lg leading-5 bg-white text-gray-900 placeholder-gray-500 focus:outline-none focus:placeholder-gray-400 focus:ring-1 ${theme.ring} ${theme.border} sm:text-sm shadow-sm`}
              placeholder="Buscar repuestos, tornillos..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>

          {/* Filters Desktop/Mobile Mixed */}
          <div className="flex gap-2 overflow-x-auto pb-2 md:pb-0 scrollbar-hide">
             {CATEGORIES.map(category => (
               <button
                key={category}
                onClick={() => setSelectedCategory(category)}
                className={`whitespace-nowrap px-4 py-2 rounded-full text-sm font-medium transition-colors ${
                  selectedCategory === category
                    ? `${theme.bg} text-white shadow-md`
                    : 'bg-white text-gray-700 hover:bg-gray-100 border border-gray-200'
                }`}
               >
                 {category}
               </button>
             ))}
          </div>
        </div>

        {/* Results Grid */}
        {filteredProducts.length > 0 ? (
          <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-6">
            {filteredProducts.map(product => (
              <ProductCard key={product.id} product={product} />
            ))}
          </div>
        ) : (
          <div className="text-center py-24">
            <Filter className="h-16 w-16 text-gray-300 mx-auto mb-4" />
            <h3 className="text-lg font-medium text-gray-900">No se encontraron productos</h3>
            <p className="text-gray-500 mt-1">Intenta con otra categoría o término de búsqueda.</p>
            <button 
              onClick={() => { setSearchTerm(''); setSelectedCategory('Todas'); }}
              className={`mt-6 ${theme.text} hover:underline font-semibold`}
            >
              Limpiar filtros
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

