import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useStore } from '../context/StoreContext';
import { CreditCard, CheckCircle, Send, Loader2 } from 'lucide-react';

const Checkout: React.FC = () => {
  const { cart, clearCart, getThemeClasses } = useStore();
  const theme = getThemeClasses();
  const navigate = useNavigate();
  const total = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);

  const [formData, setFormData] = useState({
    name: '',
    idRuc: '',      // Mapped to IDRUC
    email: '',      // Mapped to CORREO
    phone: '',      // Mapped to CELULAR
    landline: '',   // Mapped to TELEFONO
    address: '',    // Mapped to DIRECCION
    province: '',   // Mapped to PROVINCIA
  });

  const [isProcessing, setIsProcessing] = useState(false);
  const [orderComplete, setOrderComplete] = useState(false);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleOrderSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsProcessing(true);

    // 1. Homologación de campos para el JSON
    const productsSummary = cart.map(item => `${item.quantity}x ${item.name}`).join(', ');

    const payload = {
      NOMBRE: formData.name,
      IDRUC: formData.idRuc,
      TELEFONO: formData.landline || "N/A", // Campo opcional, enviamos N/A si está vacío
      CELULAR: formData.phone,
      CORREO: formData.email,
      DIRECCION: formData.address,
      PROVINCIA: formData.province,
      PRODUCTO: productsSummary,
      MONTO: total.toFixed(2)
    };

    try {
      // 2. Envío a Google Apps Script
      // Usamos mode: 'no-cors' porque Google Scripts no suele devolver cabeceras CORS standard en webapps simples.
      // Esto significa que la petición se envía, pero no podemos leer la respuesta (respuesta opaca).
      await fetch("https://script.google.com/macros/s/AKfycbzI8EcFUoRT1lvGXl8m1qMpSgz9Y0TpwOBRyGUMv7E9UMDYYi70fR2IJIG8CUF9CCwYog/exec", {
        method: "POST",
        mode: "no-cors", 
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify(payload),
      });

      // Asumimos éxito si no hubo error de red
      setOrderComplete(true);
      clearCart();

    } catch (error) {
      console.error("Error al enviar el pedido:", error);
      alert("Hubo un error al procesar tu pedido. Por favor intenta nuevamente.");
    } finally {
      setIsProcessing(false);
    }
  };

  if (cart.length === 0 && !orderComplete) {
     navigate('/catalog');
     return null;
  }

  if (orderComplete) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center p-4">
        <div className="bg-white p-8 rounded-2xl shadow-lg max-w-md w-full text-center animate-fade-in">
          <div className={`w-20 h-20 ${theme.bg} rounded-full flex items-center justify-center mx-auto mb-6 text-white`}>
            <CheckCircle size={40} />
          </div>
          <h2 className="text-2xl font-bold text-gray-900 mb-2">¡Pedido Recibido!</h2>
          <p className="text-gray-500 mb-8">
            Hemos registrado tu pedido correctamente. Te contactaremos pronto a tu celular o correo para coordinar la entrega.
          </p>
          <button
            onClick={() => navigate('/')}
            className={`w-full py-3 px-4 rounded-lg text-white font-medium ${theme.bg} ${theme.hover} transition-colors`}
          >
            Volver al Inicio
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 py-12">
      <div className="max-w-3xl mx-auto px-4 sm:px-6 lg:px-8">
        <h1 className="text-3xl font-bold text-gray-900 mb-8 text-center">Datos de Facturación y Envío</h1>

        <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
          <div className="p-8">
            <form onSubmit={handleOrderSubmit} className="space-y-6">

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                  <label htmlFor="name" className="block text-sm font-medium text-gray-700 mb-1">Nombre Completo *</label>
                  <input
                    type="text"
                    name="name"
                    required
                    className="w-full rounded-lg border-gray-300 border px-3 py-2 bg-white text-gray-900 focus:ring-2 focus:ring-emerald-500 focus:outline-none"
                    value={formData.name}
                    onChange={handleChange}
                  />
                </div>
                <div>
                  <label htmlFor="idRuc" className="block text-sm font-medium text-gray-700 mb-1">Cédula o RUC *</label>
                  <input
                    type="text"
                    name="idRuc"
                    required
                    placeholder="Ej: 8-888-888"
                    className="w-full rounded-lg border-gray-300 border px-3 py-2 bg-white text-gray-900 focus:ring-2 focus:ring-emerald-500 focus:outline-none"
                    value={formData.idRuc}
                    onChange={handleChange}
                  />
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                  <label htmlFor="phone" className="block text-sm font-medium text-gray-700 mb-1">Celular *</label>
                  <input
                    type="tel"
                    name="phone"
                    required
                    className="w-full rounded-lg border-gray-300 border px-3 py-2 bg-white text-gray-900 focus:ring-2 focus:ring-emerald-500 focus:outline-none"
                    value={formData.phone}
                    onChange={handleChange}
                  />
                </div>
                <div>
                  <label htmlFor="landline" className="block text-sm font-medium text-gray-700 mb-1">Teléfono Fijo (Opcional)</label>
                  <input
                    type="tel"
                    name="landline"
                    className="w-full rounded-lg border-gray-300 border px-3 py-2 bg-white text-gray-900 focus:ring-2 focus:ring-emerald-500 focus:outline-none"
                    value={formData.landline}
                    onChange={handleChange}
                  />
                </div>
              </div>

              <div>
                <label htmlFor="email" className="block text-sm font-medium text-gray-700 mb-1">Correo Electrónico *</label>
                <input
                  type="email"
                  name="email"
                  required
                  className="w-full rounded-lg border-gray-300 border px-3 py-2 bg-white text-gray-900 focus:ring-2 focus:ring-emerald-500 focus:outline-none"
                  value={formData.email}
                  onChange={handleChange}
                />
              </div>

              <div>
                <label htmlFor="address" className="block text-sm font-medium text-gray-700 mb-1">Dirección Exacta *</label>
                <textarea
                  name="address"
                  required
                  rows={3}
                  className="w-full rounded-lg border-gray-300 border px-3 py-2 bg-white text-gray-900 focus:ring-2 focus:ring-emerald-500 focus:outline-none"
                  value={formData.address}
                  onChange={handleChange}
                ></textarea>
              </div>

              <div>
                <label htmlFor="province" className="block text-sm font-medium text-gray-700 mb-1">Provincia *</label>
                <input
                  type="text"
                  name="province"
                  required
                  placeholder="Ej: Panamá"
                  className="w-full rounded-lg border-gray-300 border px-3 py-2 bg-white text-gray-900 focus:ring-2 focus:ring-emerald-500 focus:outline-none"
                  value={formData.province}
                  onChange={handleChange}
                />
              </div>

              <div className="bg-gray-50 p-4 rounded-lg flex justify-between items-center mt-6">
                <span className="font-semibold text-gray-700">Total a Pagar:</span>
                <span className="text-2xl font-bold text-gray-900">${total.toFixed(2)}</span>
              </div>

              <div className="pt-4 space-y-3">
                 <button
                  type="submit"
                  disabled={isProcessing}
                  className={`w-full flex items-center justify-center gap-2 ${theme.bg} ${theme.hover} text-white py-4 rounded-xl font-bold text-lg shadow-md transition-all disabled:opacity-70`}
                >
                  {isProcessing ? (
                    <>
                      <Loader2 size={24} className="animate-spin" /> Procesando...
                    </>
                  ) : (
                    <>
                      <Send size={24} /> Confirmar Pedido
                    </>
                  )}
                </button>
                <div className="text-center text-xs text-gray-500">
                   Al confirmar, enviaremos los datos de tu pedido para ser procesado.
                </div>

                <button
                   type="button"
                   disabled
                   className="w-full flex items-center justify-center gap-2 bg-gray-100 text-gray-400 py-3 rounded-xl font-semibold cursor-not-allowed"
                   title="Próximamente"
                >
                  <CreditCard size={20} /> Pago con Tarjeta (Próximamente)
                </button>
              </div>

            </form>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Checkout;

import React, { useEffect, ReactNode } from 'react';
import { HashRouter, Routes, Route, useLocation, Navigate } from 'react-router-dom';
import { StoreProvider } from './context/StoreContext';

// Components
import Navbar from './components/Navbar';
import Footer from './components/Footer';

// Pages
import Home from './pages/Home';
import Catalog from './pages/Catalog';
import ProductDetail from './pages/ProductDetail';
import Cart from './pages/Cart';
import Checkout from './pages/Checkout';
import AdminLogin from './pages/admin/AdminLogin';
import AdminDashboard from './pages/admin/AdminDashboard';

// Scroll to top on route change
const ScrollToTop = () => {
  const { pathname } = useLocation();
  useEffect(() => {
    window.scrollTo(0, 0);
  }, [pathname]);
  return null;
};

// Protected Route Wrapper
interface ProtectedRouteProps {
  children: ReactNode;
}

const ProtectedRoute: React.FC<ProtectedRouteProps> = ({ children }) => {
  const isAuthenticated = localStorage.getItem('ido_admin_auth') === 'true';
  return isAuthenticated ? <>{children}</> : <Navigate to="/admin" replace />;
};

// Layout Wrapper (Navbar + Footer only for public pages)
interface MainLayoutProps {
  children: ReactNode;
}

const MainLayout: React.FC<MainLayoutProps> = ({ children }) => {
  return (
    <div className="flex flex-col min-h-screen">
      <Navbar />
      <main className="flex-grow">
        {children}
      </main>
      <Footer />
    </div>
  );
};

const App: React.FC = () => {
  return (
    <StoreProvider>
      <HashRouter>
        <ScrollToTop />
        <Routes>
          {/* Public Routes */}
          <Route path="/" element={<MainLayout><Home /></MainLayout>} />
          <Route path="/catalog" element={<MainLayout><Catalog /></MainLayout>} />
          <Route path="/product/:id" element={<MainLayout><ProductDetail /></MainLayout>} />
          <Route path="/cart" element={<MainLayout><Cart /></MainLayout>} />
          <Route path="/checkout" element={<MainLayout><Checkout /></MainLayout>} />

          {/* Admin Routes */}
          <Route path="/admin" element={<AdminLogin />} />
          <Route 
            path="/admin/dashboard" 
            element={
              <ProtectedRoute>
                <AdminDashboard />
              </ProtectedRoute>
            } 
          />
        </Routes>
      </HashRouter>
    </StoreProvider>
  );
};

export default App;

import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useStore } from '../context/StoreContext';
import { CreditCard, CheckCircle, Send, Loader2 } from 'lucide-react';

const Checkout: React.FC = () => {
  const { cart, clearCart, getThemeClasses } = useStore();
  const theme = getThemeClasses();
  const navigate = useNavigate();
  const total = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);

  const [formData, setFormData] = useState({
    name: '',
    idRuc: '',      // Mapped to IDRUC
    email: '',      // Mapped to CORREO
    phone: '',      // Mapped to CELULAR
    landline: '',   // Mapped to TELEFONO
    address: '',    // Mapped to DIRECCION
    province: '',   // Mapped to PROVINCIA
  });

  const [isProcessing, setIsProcessing] = useState(false);
  const [orderComplete, setOrderComplete] = useState(false);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleOrderSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsProcessing(true);

    // 1. Homologación de campos para el JSON
    const productsSummary = cart.map(item => `${item.quantity}x ${item.name}`).join(', ');

    const payload = {
      NOMBRE: formData.name,
      IDRUC: formData.idRuc,
      TELEFONO: formData.landline || "N/A", // Campo opcional, enviamos N/A si está vacío
      CELULAR: formData.phone,
      CORREO: formData.email,
      DIRECCION: formData.address,
      PROVINCIA: formData.province,
      PRODUCTO: productsSummary,
      MONTO: total.toFixed(2)
    };

    try {
      // 2. Envío a Google Apps Script
      // Usamos mode: 'no-cors' porque Google Scripts no suele devolver cabeceras CORS standard en webapps simples.
      // Esto significa que la petición se envía, pero no podemos leer la respuesta (respuesta opaca).
      await fetch("https://script.google.com/macros/s/AKfycbwqu9pM57rErujaaKcQRSvSPO--J1AYig82MhFTVN0q6mjbORSfXkXx_yPbwKUqkxhv/exec", {
        method: "POST",
        mode: "no-cors", 
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify(payload),
      });

      // Asumimos éxito si no hubo error de red
      setOrderComplete(true);
      clearCart();

    } catch (error) {
      console.error("Error al enviar el pedido:", error);
      alert("Hubo un error al procesar tu pedido. Por favor intenta nuevamente.");
    } finally {
      setIsProcessing(false);
    }
  };

  if (cart.length === 0 && !orderComplete) {
     navigate('/catalog');
     return null;
  }

  if (orderComplete) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center p-4">
        <div className="bg-white p-8 rounded-2xl shadow-lg max-w-md w-full text-center animate-fade-in">
          <div className={`w-20 h-20 ${theme.bg} rounded-full flex items-center justify-center mx-auto mb-6 text-white`}>
            <CheckCircle size={40} />
          </div>
          <h2 className="text-2xl font-bold text-gray-900 mb-2">¡Pedido Recibido!</h2>
          <p className="text-gray-500 mb-8">
            Hemos registrado tu pedido correctamente. Te contactaremos pronto a tu celular o correo para coordinar la entrega.
          </p>
          <button
            onClick={() => navigate('/')}
            className={`w-full py-3 px-4 rounded-lg text-white font-medium ${theme.bg} ${theme.hover} transition-colors`}
          >
            Volver al Inicio
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 py-12">
      <div className="max-w-3xl mx-auto px-4 sm:px-6 lg:px-8">
        <h1 className="text-3xl font-bold text-gray-900 mb-8 text-center">Datos de Facturación y Envío</h1>

        <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
          <div className="p-8">
            <form onSubmit={handleOrderSubmit} className="space-y-6">

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                  <label htmlFor="name" className="block text-sm font-medium text-gray-700 mb-1">Nombre Completo *</label>
                  <input
                    type="text"
                    name="name"
                    required
                    className="w-full rounded-lg border-gray-300 border px-3 py-2 bg-white text-gray-900 focus:ring-2 focus:ring-emerald-500 focus:outline-none"
                    value={formData.name}
                    onChange={handleChange}
                  />
                </div>
                <div>
                  <label htmlFor="idRuc" className="block text-sm font-medium text-gray-700 mb-1">Cédula o RUC *</label>
                  <input
                    type="text"
                    name="idRuc"
                    required
                    placeholder="Ej: 8-888-888"
                    className="w-full rounded-lg border-gray-300 border px-3 py-2 bg-white text-gray-900 focus:ring-2 focus:ring-emerald-500 focus:outline-none"
                    value={formData.idRuc}
                    onChange={handleChange}
                  />
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                  <label htmlFor="phone" className="block text-sm font-medium text-gray-700 mb-1">Celular *</label>
                  <input
                    type="tel"
                    name="phone"
                    required
                    className="w-full rounded-lg border-gray-300 border px-3 py-2 bg-white text-gray-900 focus:ring-2 focus:ring-emerald-500 focus:outline-none"
                    value={formData.phone}
                    onChange={handleChange}
                  />
                </div>
                <div>
                  <label htmlFor="landline" className="block text-sm font-medium text-gray-700 mb-1">Teléfono Fijo (Opcional)</label>
                  <input
                    type="tel"
                    name="landline"
                    className="w-full rounded-lg border-gray-300 border px-3 py-2 bg-white text-gray-900 focus:ring-2 focus:ring-emerald-500 focus:outline-none"
                    value={formData.landline}
                    onChange={handleChange}
                  />
                </div>
              </div>

              <div>
                <label htmlFor="email" className="block text-sm font-medium text-gray-700 mb-1">Correo Electrónico *</label>
                <input
                  type="email"
                  name="email"
                  required
                  className="w-full rounded-lg border-gray-300 border px-3 py-2 bg-white text-gray-900 focus:ring-2 focus:ring-emerald-500 focus:outline-none"
                  value={formData.email}
                  onChange={handleChange}
                />
              </div>

              <div>
                <label htmlFor="address" className="block text-sm font-medium text-gray-700 mb-1">Dirección Exacta *</label>
                <textarea
                  name="address"
                  required
                  rows={3}
                  className="w-full rounded-lg border-gray-300 border px-3 py-2 bg-white text-gray-900 focus:ring-2 focus:ring-emerald-500 focus:outline-none"
                  value={formData.address}
                  onChange={handleChange}
                ></textarea>
              </div>

              <div>
                <label htmlFor="province" className="block text-sm font-medium text-gray-700 mb-1">Provincia *</label>
                <input
                  type="text"
                  name="province"
                  required
                  placeholder="Ej: Panamá"
                  className="w-full rounded-lg border-gray-300 border px-3 py-2 bg-white text-gray-900 focus:ring-2 focus:ring-emerald-500 focus:outline-none"
                  value={formData.province}
                  onChange={handleChange}
                />
              </div>

              <div className="bg-gray-50 p-4 rounded-lg flex justify-between items-center mt-6">
                <span className="font-semibold text-gray-700">Total a Pagar:</span>
                <span className="text-2xl font-bold text-gray-900">${total.toFixed(2)}</span>
              </div>

              <div className="pt-4 space-y-3">
                 <button
                  type="submit"
                  disabled={isProcessing}
                  className={`w-full flex items-center justify-center gap-2 ${theme.bg} ${theme.hover} text-white py-4 rounded-xl font-bold text-lg shadow-md transition-all disabled:opacity-70`}
                >
                  {isProcessing ? (
                    <>
                      <Loader2 size={24} className="animate-spin" /> Procesando...
                    </>
                  ) : (
                    <>
                      <Send size={24} /> Confirmar Pedido
                    </>
                  )}
                </button>
                <div className="text-center text-xs text-gray-500">
                   Al confirmar, enviaremos los datos de tu pedido para ser procesado.
                </div>

                <button
                   type="button"
                   disabled
                   className="w-full flex items-center justify-center gap-2 bg-gray-100 text-gray-400 py-3 rounded-xl font-semibold cursor-not-allowed"
                   title="Próximamente"
                >
                  <CreditCard size={20} /> Pago con Tarjeta (Próximamente)
                </button>
              </div>

            </form>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Checkout;

