import React, { useState } from 'react';
import { Package, Settings as SettingsIcon, Plus, Edit, Trash, LogOut, AlertTriangle, Image as ImageIcon, ExternalLink, AlertCircle, Check, Link as LinkIcon, Home as HomeIcon } from 'lucide-react';
import { useStore } from '../../context/StoreContext';
import { Product, Category, SiteConfig, HomeCategory, QuickLink } from '../../types';
import { THEME_COLORS } from '../../constants';
import { useNavigate } from 'react-router-dom';

const AdminDashboard: React.FC = () => {
  const { products, categories, addProduct, updateProduct, deleteProduct, addCategory, siteConfig, updateSiteConfig, getThemeClasses } = useStore();
  const theme = getThemeClasses();
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState<'inventory' | 'settings'>('inventory');

  // Product Form State
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const initialFormState: Product = {
    id: '',
    name: '',
    description: '',
    price: 0,
    category: 'Repuestos',
    imageUrl: '',
    stock: 0
  };
  const [formData, setFormData] = useState<Product>(initialFormState);

  // New Category State
  const [isAddingCategory, setIsAddingCategory] = useState(false);
  const [newCategoryName, setNewCategoryName] = useState('');

  // Delete Confirmation State
  const [isDeleteModalOpen, setIsDeleteModalOpen] = useState(false);
  const [productToDelete, setProductToDelete] = useState<Product | null>(null);

  // Settings Form State
  const [configForm, setConfigForm] = useState<SiteConfig>(siteConfig);

  const handleOpenModal = (product?: Product) => {
    setIsAddingCategory(false);
    setNewCategoryName('');
    if (product) {
      setEditingProduct(product);
      setFormData(product);
    } else {
      setEditingProduct(null);
      setFormData({ ...initialFormState, id: Date.now().toString() });
    }
    setIsModalOpen(true);
  };

