                      <input 
                        type="text" 
                        className="flex-1 border rounded px-3 py-2 text-sm bg-white text-gray-900"
                        placeholder="URL (Ej: /catalog o https://...)"
                        value={link.url}
                        onChange={(e) => updateQuickLink(index, 'url', e.target.value)}
                      />
