import { Product, Category, SiteConfig, HomeCategory, QuickLink, ProductVariant } from '../../types';
import { THEME_COLORS } from '../../constants';
import { useNavigate } from 'react-router-dom';

const AdminDashboard: React.FC = () => {
  const { products, categories, addProduct, updateProduct, deleteProduct, addCategory, siteConfig, updateSiteConfig, getThemeClasses, resetStore } = useStore();
  const theme = getThemeClasses();
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState<'inventory' | 'settings'>('inventory');

  // Product Form State
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const initialFormState: Product = {
    id: '',
    name: '',
    description: '',
    price: 0,
    category: 'Repuestos',
    imageUrl: '',
    stock: 0,
    variants: []
  };
  const [formData, setFormData] = useState<Product>(initialFormState);

  // Variant Management State
  const [hasVariants, setHasVariants] = useState(false);
  const [newVariant, setNewVariant] = useState<ProductVariant>({
    id: '',
    name: '',
    price: 0,
    stock: 0
  });

  // New Category State
  const [isAddingCategory, setIsAddingCategory] = useState(false);
  const [newCategoryName, setNewCategoryName] = useState('');

  // Delete Confirmation State
  const [isDeleteModalOpen, setIsDeleteModalOpen] = useState(false);
  const [productToDelete, setProductToDelete] = useState<Product | null>(null);
  const [isResetConfirmOpen, setIsResetConfirmOpen] = useState(false);

  // Settings Form State
  const [configForm, setConfigForm] = useState<SiteConfig>(siteConfig);

  const handleOpenModal = (product?: Product) => {
    setIsAddingCategory(false);
    setNewCategoryName('');
    if (product) {
      setEditingProduct(product);
      setFormData(product);
      setHasVariants(!!(product.variants && product.variants.length > 0));
    } else {
      setEditingProduct(null);
      setFormData({ ...initialFormState, id: Date.now().toString() });
      setHasVariants(false);
    }
    // Reset variant input
    setNewVariant({ id: '', name: '', price: 0, stock: 0 });
    setIsModalOpen(true);
  };

  const handleProductSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const finalProduct = { ...formData };

    // If variants are enabled, ensure price/stock reflects base or logic, 
    // but typically we keep the form data as is or calculate totals.
    // Here we just save what is in formData (which includes variants array).
    if (!hasVariants) {
        finalProduct.variants = [];
    }

    if (editingProduct) {
      updateProduct(finalProduct);
    } else {
      addProduct(finalProduct);
    }
    setIsModalOpen(false);
  };

  // Variant Helpers
  const addVariant = () => {
    if (!newVariant.name) return alert("Nombre de variante requerido");
    const variantToAdd = { ...newVariant, id: Date.now().toString() };
    const updatedVariants = [...(formData.variants || []), variantToAdd];
    setFormData({ ...formData, variants: updatedVariants });
    setNewVariant({ id: '', name: '', price: 0, stock: 0 }); // Reset
  };

  const removeVariant = (id: string) => {
    const updatedVariants = (formData.variants || []).filter(v => v.id !== id);
    setFormData({ ...formData, variants: updatedVariants });
  };

  const handleCreateCategory = () => {
    if (newCategoryName.trim()) {
      addCategory(newCategoryName.trim());
      setFormData({...formData, category: newCategoryName.trim()});
      setIsAddingCategory(false);
      setNewCategoryName('');
    }
  };

  const handleDeleteClick = (product: Product) => {
    setProductToDelete(product);
    setIsDeleteModalOpen(true);
  };

  const confirmDelete = () => {
    if (productToDelete) {
      deleteProduct(productToDelete.id);
      setIsDeleteModalOpen(false);
      setProductToDelete(null);
    }
  };

  const cancelDelete = () => {
    setIsDeleteModalOpen(false);
    setProductToDelete(null);
  };

  const handleSettingsSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    updateSiteConfig(configForm);
    alert('Configuración actualizada en el navegador.');
  };

  const handleLogout = () => {
    localStorage.removeItem('ido_admin_auth');
    navigate('/admin');
  };

  // --- LOGIC TO GENERATE AND DOWNLOAD CODE ---

  const generateFullFileContent = () => {
    // We recreate the THEME_COLORS object string manually to ensure it's included in the file
    const themeColorsString = `export const THEME_COLORS = {
  green: { bg: 'bg-emerald-600', text: 'text-emerald-600', border: 'border-emerald-600', hover: 'hover:bg-emerald-700', ring: 'focus:ring-emerald-500', btnHover: 'hover:bg-emerald-700' },
  blue: { bg: 'bg-blue-600', text: 'text-blue-600', border: 'border-blue-600', hover: 'hover:bg-blue-700', ring: 'focus:ring-blue-500', btnHover: 'hover:bg-blue-700' },
  orange: { bg: 'bg-orange-600', text: 'text-orange-600', border: 'border-orange-600', hover: 'hover:bg-orange-700', ring: 'focus:ring-orange-500', btnHover: 'hover:bg-orange-700' },
  red: { bg: 'bg-red-600', text: 'text-red-600', border: 'border-red-600', hover: 'hover:bg-red-700', ring: 'focus:ring-red-500', btnHover: 'hover:bg-red-700' },
};`;

